function Auto_AddNewItem()
{
  let ss = SpreadsheetApp.getActiveSpreadsheet();
  // Acceder al intervalo por su nombre

  let ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");

  if (ranges["ok"])
  {
    let values = ranges["input"].getValues();
    let itemID = values[1][0];
    let itemName = values[1][1];
    let itemSprite = values[1][2];
    let itemSpritePickable = itemSprite.replace("SPRITE_","SPRITE_PICKABLE_");
    let obtainItemEventName = "EVENT_" + itemID + "_PICKABLE_TAKEN";
    let observeItemPhraseName = "PHRASE_OBSERVE_" + itemID;
    let takeItemPhraseName = "PHRASE_TAKE_" + itemID;
    let observeItemConditionName = "COND_OBSERVE_" + itemID;
    let actionObserveItemName = "ACTION_DIALOGUE_OBSERVE_" + itemID;
    let actionTakeItemName = "ACTION_DIALOGUE_TAKE_" + itemID;
    let takeItemConditionName = "COND_TAKE_" + itemID;
    let itemPickable = (values[1][3].toString().toLowerCase() == "true")
    let itemSpawn = (values[1][4].toString().toLowerCase() == "true")
    let pickerChar = values[1][5];
    let observeItemPhraseContent = values[1][6];
    let takeItemPhraseContent = values[1][7]
    let itemRoom = values[1][8];





    /* Add name */
    Name_Range_AddName(ranges["name"], itemName, itemName);

    /* Add sprite */
    Sprites_Range_AddSprite(ranges["sprites"], itemSprite, "SPRITE_ATLAS_INVALID_01");

    /* Observation phrase (and action) */

    if(observeItemPhraseContent.length > 0)
    {
      let newPhraseID = Phrase_Range_AddPhrase(ranges["phrases"], observeItemPhraseName, observeItemPhraseContent);
      let newActionID = Actions_Range_AddAction_DialogSimple(ranges["actions"], actionObserveItemName, newPhraseID);
      observeItemConditionName = ItemActions_Range_AddCondition(ranges["action_conds"], observeItemConditionName, "INTERACTION_OBSERVE", pickerChar, newActionID);
    }
    else
    {
      observeItemConditionName = "";
    }

    ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");

    let itemConditions = observeItemConditionName;

    if(itemPickable)
    {
      /* Event obtain */
      obtainItemEventName = Events_Range_AddEvent(ranges["events"], obtainItemEventName);

      /* If pickable sprite does not already exist, insert new row with name */
      Sprites_Range_AddSprite(ranges["sprites"], itemSpritePickable, "SPRITE_ATLAS_INVALID_01");

      /* Take phrase (and action) */
      if(takeItemPhraseContent.length > 0)
      {
        let newPhraseID = Phrase_Range_AddPhrase(ranges["phrases"], takeItemPhraseName, takeItemPhraseContent);
        let newActionID = Actions_Range_AddAction_DialogSimple(ranges["actions"], actionTakeItemName, newPhraseID);
        takeItemConditionName = ItemActions_Range_AddCondition(ranges["action_conds"], takeItemConditionName, "INTERACTION_TAKE", pickerChar, newActionID);

        if(itemConditions.length > 0)
        {
          itemConditions += ", " + takeItemConditionName;
        }
        else
        {
          itemConditions = takeItemConditionName;
        }
      }

      ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");
    }

    if(itemConditions.length == 0)
    {
      itemConditions = "COND_OK";
    }

    /* Finally, add item */
    itemID = Items_Range_AddItem(ranges["items"], itemID, itemName, itemSprite, itemSpritePickable, itemPickable, itemConditions);

    if(itemPickable && (itemRoom != "ROOM_NONE"))
    {
      /* Destroy Unchainer when taking */
      let newActionID = Actions_Range_AddAction_Spawn(ranges["actions"], "ACTION_DESTROY_"+itemID, itemID, true, false);
      Unchainers_Range_AddUnchainer_Spawn(ranges["unchain_conds"], "UNCHAINER_"+itemID+"_TAKE_1", obtainItemEventName, true, newActionID);

      ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");

      /* Obtain intem officially */
      newActionID = Actions_Range_AddAction_ObtainItem(ranges["actions"], "ACTION_OBTAIN_"+itemID, itemID, pickerChar);

      ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");

      ItemActions_Range_Condition_AddAction(ranges["action_conds"], takeItemConditionName, newActionID);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");
    }

    if(itemSpawn)
    {
      let newActionID = Actions_Range_AddAction_Spawn(ranges["actions"], "ACTION_DESPAWN_"+itemID, itemID, false, false);
      Unchainers_Range_AddUnchainer_Spawn(ranges["unchain_conds"], "UNCHAINER_"+itemID+"_DESPAWN", "EVENT_NONE", false, newActionID);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");

      newActionID = Actions_Range_AddAction_Spawn(ranges["actions"], "ACTION_DESPAWN_"+itemID, itemID, false, true);
      Unchainers_Range_AddUnchainer_Spawn(ranges["unchain_conds"], "UNCHAINER_"+itemID+"_SPAWN", "EVENT_NONE", false, newActionID);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertItem");
    }

    /* Add it to its room */
    if(itemRoom != "ROOM_NONE")
    {
      Rooms_Range_AddNeededItems(ranges["rooms"], itemRoom, itemID);
    }
  } 
  else
  {
    Logger.log("Some interval does not exist");
  }
}

function Auto_AddNewRoom()
{
  let ss = SpreadsheetApp.getActiveSpreadsheet();
  // Acceder al intervalo por su nombre

  let ranges = GetWorkingIntervals(ss, "Interval_autoInsertRoom");

  if (ranges["ok"])
  {
    let values = ranges["input"].getValues();
    let roomID = values[1][0];
    let backgroundName = values[1][1];
    let backgroundNightName = values[1][2];
    let musicName = values[1][3];

    Sprites_Range_AddSprite(ranges["sprites"], backgroundName, "SPRITE_ATLAS_UNDEFINED_01");
    ranges = GetWorkingIntervals(ss, "Interval_autoInsertRoom");
    Sprites_Range_AddSprite(ranges["sprites"], backgroundNightName, "SPRITE_ATLAS_UNDEFINED_01");
    ranges = GetWorkingIntervals(ss, "Interval_autoInsertRoom");
    Sounds_Range_AddSound(ranges["sounds"], musicName);
    ranges = GetWorkingIntervals(ss, "Interval_autoInsertRoom");

    Rooms_Range_AddRoom(ranges["rooms"], roomID, backgroundName, backgroundNightName, musicName);
  } 
  else
  {
    Logger.log("Some interval does not exist");
  }
}

function Auto_AddNewDialog()
{
  let ss = SpreadsheetApp.getActiveSpreadsheet();
  // Acceder al intervalo por su nombre

  let ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");

  if (ranges["ok"])
  {
    /** @type {string[]} */
    let values = ranges["input"].getValues();

    let dialogID = values[1][0];
    let introPhrases = values[1][1];
    let talkers = values[1][2];

    /* Add an event to obtain item */
    let availableDialogs = ranges["dialogs"].getValues().map(fila => fila[1]);
    while(availableDialogs.includes(dialogID))
    {
      dialogID += "_01";
    }

    let dialogIntroID = dialogID + "_INTRO";
    while(availableDialogs.includes(dialogIntroID))
    {
      dialogIntroID += "_01";
    }

    /** @type {string[]} */
    let optionPhrases = [];
    for(let i = 3; i < 9; i++)
    {
      if(values[1][i].length > 0)
      {
        optionPhrases.push(values[1][i]);
      }
    }

    let createdDialogOptions = "";

    /* Create options phrases */
    for(let i = 0; i < optionPhrases.length; i++)
    {
      let subphrases = optionPhrases[i].split(", ");
      let createdPhraseIDs = "";

      for(let e = 0; e < subphrases.length; e++)
      {
        let newPhraseID = Phrase_Range_AddPhrase(ranges["phrases"], "PHRASE_"+dialogID+"_OPTION_"+i.toString()+"_"+e.toString(), subphrases[e]);
        ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");
        if(e > 0)
        {
          createdPhraseIDs += ", ";
        }
        createdPhraseIDs += newPhraseID;
      }

      let newDialogOptionID = Dialogs_Range_AddDialogOption(ranges["dialog_opts"], dialogID + "_OPTION_" + i.toString(), dialogID, false, createdPhraseIDs);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");
      if(i > 0)
      {
        createdDialogOptions += ", ";
      }
      createdDialogOptions += newDialogOptionID;
    }

    Dialogs_Range_AddDialog(ranges["dialogs"], dialogID, talkers, createdDialogOptions);
    ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");


    if(introPhrases.length == 0)
    {
      /* No intro phrase, direct dialog options */
    }
    else if(introPhrases.includes(", "))
    {
      /* Randomized intro phrases */
      let introPhrasesArray = introPhrases.split(", ");
      let introPhrasesIDs = "";
      for(let i=0; i < introPhrasesArray.length; i++)
      {
        let newPhraseID = Phrase_Range_AddPhrase(ranges["phrases"], "PHRASE_"+dialogIntroID+"_"+i.toString(), introPhrasesArray[i]);
        ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");
        if(i > 0)
        {
          introPhrasesIDs += ", ";
        }
        introPhrasesIDs += newPhraseID;
      }
      let newDialogOptionID = Dialogs_Range_AddDialogOption(ranges["dialog_opts"], dialogID+"_OPTION_INTRO", dialogID, true, introPhrasesIDs);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");
      Dialogs_Range_AddDialog(ranges["dialogs"], dialogIntroID, talkers, newDialogOptionID);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");
    }
    else
    {
      /* Single intro */
      let newPhraseID = Phrase_Range_AddPhrase(ranges["phrases"], "PHRASE_"+dialogIntroID, introPhrases);
      let newDialogOptionID = Dialogs_Range_AddDialogOption(ranges["dialog_opts"], dialogID+"_OPTION_INTRO", dialogID, false, newPhraseID);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");
      Dialogs_Range_AddDialog(ranges["dialogs"], dialogIntroID, talkers, newDialogOptionID);
      ranges = GetWorkingIntervals(ss, "Interval_autoInsertDialog");
    }


  } 
  else
  {
    Logger.log("Some interval does not exist");
  }
}

function Auto_AddNewMemento()
{
  let ss = SpreadsheetApp.getActiveSpreadsheet();
  // Acceder al intervalo por su nombre

  let ranges = GetWorkingIntervals(ss, "Interval_autoInsertMemento");

  if (ranges["ok"])
  {
    /** @type {string[]} */
    let values = ranges["input"].getValues();

    let mementoParentID = values[1][0];
    let mementoIconSpriteID = values[1][1];
    let mementoParentName = values[1][2];
    let mementosIDs = values[1][3];
    let mementosPhrases = values[1][4];

    let mementoIDArray = mementosIDs.split(", ");
    let mementoPhrasesArray = mementosPhrases.split(", ");

    if(mementoIDArray.length != mementoPhrasesArray.length)
    {
      Logger.log("IDs and phrases for mementos don't match in length");
      return;
    }

    /* Get parent memento used ID */
    let availableParentMementos = ranges["memento_parent"].getValues().map(fila => fila[1]);
    while(availableParentMementos.includes(mementoParentID))
    {
      mementoParentID += "_01";
    }

    Sprites_Range_AddSprite(ranges["sprites"], mementoIconSpriteID, "SPRITE_ATLAS_MEMENTOS");
    Name_Range_AddName(ranges["name"], "NAME_" + mementoParentID, mementoParentName);
    mementoParentID = Memento_Parent_Range_AddMementoParent(ranges["memento_parent"], mementoParentID, "NAME_" + mementoParentID, mementoIconSpriteID);

    ranges = GetWorkingIntervals(ss, "Interval_autoInsertMemento");


    for(let i=0; i < mementoIDArray.length; i++)
    {
      let newMementoPhraseID = Phrase_Range_AddPhrase(ranges["phrases"], "PHRASE_"+mementoIDArray[i], mementoPhrasesArray[i]);
      let newMementoID = Memento_Range_AddMemento(ranges["memento"], mementoIDArray[i], mementoParentID, newMementoPhraseID, i==(mementoIDArray.length-1));

      ranges = GetWorkingIntervals(ss, "Interval_autoInsertMemento");
    }
  } 
  else
  {
    Logger.log("Some interval does not exist");
  }
}

/**
 * @param {SpreadsheetApp.Spreadsheet} ss - Spreadsheet
 * @param {string} inputRangeName - inputRangeName
 * @returns {SpreadsheetApp.Range[]} Container
 */
function GetWorkingIntervals(ss, inputRangeName)
{
  var retVal = {};
  retVal["input"] = ss.getRangeByName(inputRangeName);
  retVal["items"] = ss.getRangeByName("Interval_Items");
  retVal["action_conds"] = ss.getRangeByName("Interval_Action_Conditions");
  retVal["name"] = ss.getRangeByName("Interval_Name");
  retVal["phrases"] = ss.getRangeByName("Interval_Phrases");
  retVal["sprites"] = ss.getRangeByName("Interval_sprites");
  retVal["sounds"] = ss.getRangeByName("Interval_Sounds");
  retVal["animations"] = ss.getRangeByName("Interval_Animations");
  retVal["events"] = ss.getRangeByName("Interval_Events");
  retVal["rooms"] = ss.getRangeByName("Interval_Rooms");
  retVal["unchain_conds"] = ss.getRangeByName("Interval_Unchain_Conditions");
  retVal["actions"] = ss.getRangeByName("Interval_Actions");
  retVal["memento"] = ss.getRangeByName("Interval_Memento");
  retVal["memento_parent"] = ss.getRangeByName("Interval_Memento_Parent");
  retVal["dialogs"] = ss.getRangeByName("Interval_Dialogs");
  retVal["dialog_opts"] = ss.getRangeByName("Interval_Dialog_Options");

  retVal["ok"] = (retVal["input"] != null) && (retVal["items"] != null) && (retVal["action_conds"] != null);
  retVal["ok"] &= (retVal["name"] != null) && (retVal["phrases"] != null) && (retVal["sprites"] != null) && (retVal["sounds"] != null) && (retVal["animations"] != null);
  retVal["ok"] &= (retVal["events"] != null) && (retVal["rooms"] != null) && (retVal["unchain_conds"] != null) && (retVal["actions"] != null) && (retVal["memento"] != null);
  retVal["ok"] &= (retVal["memento_parent"] != null) && (retVal["dialogs"] != null) && (retVal["dialog_opts"] != null);


  return retVal;
}

/**
 * @param {SpreadsheetApp.Range} range - range
 * @return {SpreadsheetApp.Range} destRange
 */
function InsertRowBeforeEnd(range)
{
  const hoja = range.getSheet();
  const filaInicio = range.getRow();
  const numFilas = range.getNumRows();
  const numColumnas = range.getNumColumns();
  const columnaInicio = range.getColumn();

  // 2. Calcular posiciones
  // La última fila del range es: filaInicio + numFilas - 1
  // La penúltima fila es esa menos 1.
  const ultimaFilaAbsoluta = filaInicio + numFilas - 1;
  const penultimaFilaAbsoluta = ultimaFilaAbsoluta - 1;

  // 3. Insertar una fila vacía justo antes de la última
  // Al insertar en la posición de la 'última', la que era última baja un lugar
  hoja.insertRowBefore(ultimaFilaAbsoluta);

  // 4. Copiar el contenido de la penúltima a la nueva fila creada
  // El origen es la penúltima (que no se movió)
  const origen = hoja.getRange(penultimaFilaAbsoluta, columnaInicio, 1, numColumnas);

  // El destino es la fila que acabamos de insertar (que ahora ocupa la posición 'ultimaFilaAbsoluta')
  const destino = hoja.getRange(ultimaFilaAbsoluta, columnaInicio, 1, numColumnas);

  origen.copyTo(destino);

  const destinoWoutIndex = hoja.getRange(ultimaFilaAbsoluta, columnaInicio + 1, 1, numColumnas - 1);

  return destinoWoutIndex;
}

/**
 * @param {SpreadsheetApp.Range} conditionsRange - conditionsRange
 * @param {string} conditionIDInput - conditionIDInput
 * @param {string} interaction_type - interaction_type
 * @param {string} sourceChar - sourceChar
 * @param {string} actionID - actionID
 * @returns {string} itemConditionID
 */
function ItemActions_Range_AddCondition(conditionsRange, conditionIDInput, interaction_type, sourceChar, actionID)
{
  let availableConds = conditionsRange.getValues().map(fila => fila[1]);
  let itemConditionID = conditionIDInput;
  while(availableConds.includes(itemConditionID))
  {
    itemConditionID += "_01";
  }
  let newCondRow = InsertRowBeforeEnd(conditionsRange);
  let newCondArray = newCondRow.getValues();
  newCondArray[0][0] = itemConditionID;
  newCondArray[0][1] = "EVENT_NONE";
  newCondArray[0][2] = "MOMENT_ANY";
  newCondArray[0][3] = sourceChar;
  newCondArray[0][4] = "ITEM_NONE";
  newCondArray[0][5] = interaction_type;
  newCondArray[0][6] = actionID;

  newCondRow.setValues(newCondArray);

  return itemConditionID;
}

/**
 * @param {SpreadsheetApp.Range} conditionsRange - actionsRange
 * @param {string} conditionID - actionIDInput
 * @param {string} newActionID - actionID
 */
function ItemActions_Range_Condition_AddAction(conditionsRange, conditionID, newActionID)
{
  /* Add to desired condition (If exists) */
  let conditionsArray = conditionsRange.getValues();
  let conditionsSheet = conditionsRange.getSheet();

  for(let i=1; i < conditionsArray.length; i++)
  {
    if(conditionsArray[i][1] == conditionID)
    {
      let actionsRange = conditionsSheet.getRange(conditionsRange.getRow()+i, 8, 1, 1);
      let actionsArray = actionsRange.getValues();
      actionsArray[0][0] += ", " + newActionID;
      actionsRange.setValues(actionsArray);
      break;
    }
  }
}

/**
 * @param {SpreadsheetApp.Range} phrasesRange - phrasesRange
 * @param {string} phraseIDInput - phraseIDInput
 * @param {string} phraseContent - phraseContent
 * @returns {string} phraseID
 */
function Phrase_Range_AddPhrase(phrasesRange, phraseIDInput, phraseContent)
{
  let phraseID = phraseIDInput;
  let availablePhrases = phrasesRange.getValues().map(fila => fila[1]);
  while(availablePhrases.includes(phraseID))
  {
    phraseID += "_01";
  }
  let newPhraseRow = InsertRowBeforeEnd(phrasesRange);
  let newPhraseArray = newPhraseRow.getValues();
  newPhraseArray[0][0] = phraseID;
  newPhraseArray[0][1] = 0;
  newPhraseArray[0][2] = "SOUND_NONE";
  newPhraseArray[0][3] = "DIALOG_ANIMATION_TALK";

  for(let i=4; i < newPhraseArray[0].length; i++)
  {
    newPhraseArray[0][i] = phraseContent;
  }
  newPhraseRow.setValues(newPhraseArray);

  return phraseID;
}

/**
 * @param {SpreadsheetApp.Range} nameRange - nameRange
 * @param {string} nameIDInput - nameIDInput
 * @param {string} nameContent - nameContent
 */
function Name_Range_AddName(nameRange, nameIDInput, nameContent)
{
  /* If name does not already exist, insert new row with name */
  let availableNames = nameRange.getValues().map(fila => fila[1]);
  if(!availableNames.includes(nameIDInput))
  {
    let newNameRow = InsertRowBeforeEnd(nameRange);
    let languageNames = newNameRow.getValues();

    languageNames[0][0] = nameIDInput;
    for(let i = 1; i < languageNames[0].length; i++)
    {
      languageNames[0][i] = nameContent;
    }
    newNameRow.setValues(languageNames);
  }
}

/**
 * @param {SpreadsheetApp.Range} spritesRange - spritesRange
 * @param {string} spriteIDInput - spriteIDInput
 * @param {string} spriteAtlas - spriteAtlas
 */
function Sprites_Range_AddSprite(spritesRange, spriteIDInput, spriteAtlas)
{
  /* If sprite does not already exist, insert new row with name */
    let availableSprites = spritesRange.getValues().map(fila => fila[1]);
    if(!availableSprites.includes(spriteIDInput))
    {
      let newSpriteRow = InsertRowBeforeEnd(spritesRange);
      let newSpriteArray = newSpriteRow.getValues();
      newSpriteArray[0][0] = spriteIDInput;
      newSpriteArray[0][1] = spriteAtlas + "[" + spriteIDInput + "]";
      newSpriteRow.setValues(newSpriteArray);
    }
}

/**
 * @param {SpreadsheetApp.Range} soundsRange - spritesRange
 * @param {string} soundIDInput - soundIDInput
 */
function Sounds_Range_AddSound(soundsRange, soundIDInput)
{
  /* If sprite does not already exist, insert new row with name */
    let availableSounds = soundsRange.getValues().map(fila => fila[1]);
    if(!availableSounds.includes(soundIDInput))
    {
      let newSoundRow = InsertRowBeforeEnd(soundsRange);
      let newSoundArray = newSoundRow.getValues();
      newSoundArray[0][0] = soundIDInput;
      newSoundArray[0][1] = "EFFECT_NONE";
      newSoundArray[0][2] = soundIDInput;
      newSoundRow.setValues(newSoundArray);
    }
}

/**
 * @param {SpreadsheetApp.Range} eventsRange - eventsRange
 * @param {string} eventIDInput - eventIDInput
 * @returns {string} eventID
 */
function Events_Range_AddEvent(eventsRange, eventIDInput)
{
  let eventID = eventIDInput;

  /* Add an event to obtain item */
  let availableEvents = eventsRange.getValues().map(fila => fila[1]);
  while(availableEvents.includes(eventID))
  {
    eventID += "_01";
  }

  let newEventRow = InsertRowBeforeEnd(eventsRange);
  let newEventArray = newEventRow.getValues();
  newEventArray[0][0] = eventID;
  newEventRow.setValues(newEventArray);

  return eventID;
}

/**
 * @param {SpreadsheetApp.Range} itemsRange - itemsRange
 * @param {string} itemIDInput - itemIDInput
 * @param {string} nameID - nameID
 * @param {string} spriteID - spriteID
 * @param {string} spriteIDPickable - spriteIDPickable
 * @param {boolean} pickable - pickable
 * @param {string} conditions - conditions
 * @returns {string} itemID
 */
function Items_Range_AddItem(itemsRange, itemIDInput, nameID, spriteID, spriteIDPickable, pickable, conditions)
{
  let itemID = itemIDInput;

  /* Add an event to obtain item */
  let availableItems = itemsRange.getValues().map(fila => fila[1]);
  while(availableItems.includes(itemID))
  {
    itemID += "_01";
  }

  /* Copy content of last but one to the new last but one (Insert a copy) */
  let newItemRange = InsertRowBeforeEnd(itemsRange);

  /* Give format to new item */
  let newItemArray = newItemRange.getValues();
  newItemArray[0][0] = itemID;
  newItemArray[0][1] = nameID;
  newItemArray[0][2] = "ITEM_FAMILY_TYPE_OBJECT";
  newItemArray[0][3] = spriteID;
  newItemArray[0][4] = spriteID;
  newItemArray[0][5] = pickable ? "TRUE" : "FALSE";
  newItemArray[0][6] = pickable ? spriteIDPickable : "SPRITE_NONE";
  newItemArray[0][7] = "DETAIL_NONE";
  newItemArray[0][8] = conditions;

  newItemRange.setValues(newItemArray);

  return itemID;
}

/**
 * @param {SpreadsheetApp.Range} roomsRange - roomsRange
 * @param {string} roomID - roomID
 * @param {string} itemID - itemID
 */
function Rooms_Range_AddNeededItems(roomsRange, roomID, itemID)
{
  /* Add to desired room (If exists) */
  let roomsArray = roomsRange.getValues();
  let roomsSheet = roomsRange.getSheet();

  for(let i=1; i < roomsArray.length; i++)
  {
    if(roomsArray[i][1] == roomID)
    {
      let neededItemsRange = roomsSheet.getRange(roomsRange.getRow()+i, 6, 1, 1);
      let neededItemsArray = neededItemsRange.getValues();
      neededItemsArray[0][0] += ", " + itemID;
      neededItemsRange.setValues(neededItemsArray);
      break;
    }
  }
}

/**
 * @param {SpreadsheetApp.Range} roomsRange - roomsRange
 * @param {string} roomIDInput - roomIDInput
 * @param {string} bakcgroundID - bakcgroundID
 * @param {string} bakcgroundNightID - bakcgroundNightID
 * @param {string} musicID - musicID
 * @returns {string} roomID
 */
function Rooms_Range_AddRoom(roomsRange, roomIDInput, bakcgroundID, bakcgroundNightID, musicID)
{
  let roomID = roomIDInput;

  /* Add an event to obtain item */
  let availableRooms = roomsRange.getValues().map(fila => fila[1]);
  while(availableRooms.includes(roomID))
  {
    roomID += "_01";
  }

  let needed_bckgs = bakcgroundID + ", " + bakcgroundNightID;

  let newRoomRow = InsertRowBeforeEnd(roomsRange);
  let hoja = roomsRange.getSheet();

  /* Room rows have formulas, it is important to use value ranges which not involve formulas */
  let edit_range = hoja.getRange(newRoomRow.getRow(), 2, 1, 9);
  let edit_array = edit_range.getValues();

  edit_array[0][0] = roomID;
